import React from "react";

function Login() {
  return (
    <div style={{ textAlign: "center" }}>
      <h2>Login Page</h2>

      <input placeholder="Username" />
      <br /><br />

      <input type="password" placeholder="Password" />
      <br /><br />

      <button>Login</button>
    </div>
  );
}

export default Login;
